import { Component, inject, signal, computed } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterModule } from '@angular/router';
import { toSignal, toObservable } from '@angular/core/rxjs-interop';
import { of, catchError, tap, switchMap } from 'rxjs';

import { AppInstallFacadeService } from '../../services/app-install-facade.service';
import { AppStoreService } from '../../services/app-store.service';
import { ClientDataService } from '../../../clients/services/client-data.service';
import { AppDefinitionListItem } from '../../models/app-store.models';
import { isNullOrUndefined } from '../../../../shared/utils';

import { ButtonModule } from 'primeng/button';
import { CardModule } from 'primeng/card';
import { ProgressSpinnerModule } from 'primeng/progressspinner';
import { TooltipModule } from 'primeng/tooltip';
import { AppCardComponent } from '../../components/app-card/app-card.component';

@Component({
  selector: 'app-my-installed-apps',
  imports: [
    CommonModule,
    RouterModule,
    ButtonModule,
    CardModule,
    ProgressSpinnerModule,
    TooltipModule,
    AppCardComponent,
  ],
  templateUrl: './my-installed-apps.component.html',
  styleUrls: ['./my-installed-apps.component.scss'],
})
export class MyInstalledAppsComponent {
  private readonly installFacade = inject(AppInstallFacadeService);
  private readonly appStoreService = inject(AppStoreService);
  readonly actionAppId = signal<string | null>(null);
  private readonly clientDataService = inject(ClientDataService);

  // State Signals
  readonly isLoading = signal(true);
  readonly error = signal<string | null>(null);
  readonly currentClientId = computed(
    () => this.clientDataService.getSelectedClient()?.id,
  );

  // Refresh trigger
  private readonly refreshTrigger = signal(0);

  // Single call returns apps with installation context already embedded
  readonly installedApps = toSignal(
    toObservable(this.refreshTrigger).pipe(
      tap(() => this.isLoading.set(true)),
      switchMap(() => {
        const clientId = this.currentClientId();
        if (isNullOrUndefined(clientId)) {
          this.isLoading.set(false);
          return of([] as AppDefinitionListItem[]);
        }

        return this.appStoreService.getOrganisationInstalledApps(clientId).pipe(
          tap(() => this.isLoading.set(false)),
          catchError((err) => {
            console.error('Error loading installed apps:', err);
            this.error.set('Unable to load your installed apps.');
            this.isLoading.set(false);
            return of([] as AppDefinitionListItem[]);
          }),
        );
      }),
    ),
    { initialValue: [] as AppDefinitionListItem[] },
  );

  readonly filteredApps = computed(() => this.installedApps() ?? []);

  readonly hasInstalledApps = computed(() => this.filteredApps().length > 0);

  refresh(): void {
    this.error.set(null);
    this.refreshTrigger.update((n) => n + 1);
  }

  uninstallApp(app: AppDefinitionListItem): void {
    if (isNullOrUndefined(app.installation?.id)) return;
    const isExternalApp =
      app.integrationPoints?.some((p) => p.screenId === 'appSidebar') ?? false;

    this.actionAppId.set(app.id);
    this.installFacade.uninstallApp(app.installation?.id, isExternalApp, () => {
      this.actionAppId.set(null);
      this.refresh();
    });
  }
}
